```cpp
#include <iostream>

template <typename T>
class Swapper {
    T m_a;
    T m_b;
public:
    Swapper(T a, T b) : m_a{ a }, m_b{ b } {}
    void swap() {
        T tmp = m_a;
        m_a   = m_b;
        m_b   = tmp;
    }
    T first()  const { return m_a; }
    T second() const { return m_b; }
};

int main() {
    Swapper<int> s{ 1, 2 };
    s.swap();
    std::cout << s.first() << " " << s.second() << "\n";
}
